mapper.select:
SELECT i.item_id, i.item_name, i.item_img, f.user_id, f.created_at
FROM fridge_item f
         JOIN items i ON f.item_id = i.item_id
WHERE f.user_id = #{userId}
ORDER BY f.created_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM fridge_item
WHERE user_id = #{userId}

mapper.delete:
DELETE
FROM fridge_item
WHERE user_id = #{userId}
  AND item_id = #{itemId}
